        const classDate = new Date(checkDate);
        classDate.setHours(hour, minute, 0, 0);

        if (classDate > now) {
          return {
            date: classDate,
            dayName: i === 0 ? 'Today' : (i === 1 ? 'Tomorrow' : dayName),
            time: formatTime(time),
            todayHoliday: todayHoliday
          };
        }
      }
    }

    return { todayHoliday };
  };

  const nextClassInfo = getNextClass();

