    }

    if (support.isIOS && !support.isStandalone) {
      alert("To enable notifications on iPhone, please tap 'Share' then 'Add to Home Screen' first.");
      setIsSidebarOpen(false);
      return;
    }

    const token = await requestForToken(member.phone);

