    const todayHoliday = holidays[todayStr];

    for (let i = 0; i < 7; i++) {
      const checkDate = new Date(now);
      checkDate.setDate(now.getDate() + i);
      const dayName = days[checkDate.getDay()];
      const dateString = checkDate.toISOString().split('T')[0];

