               )}
            </div>

            {info.isHoliday ? (
               <div className={`text-center py-8 rounded-xl border ${info.isClosed ? 'bg-red-500/5 border-red-500/10' : 'bg-orange-500/5 border-orange-500/10'}`}>
                  {info.isClosed ? (
