/**
 * Helper to log analytics events with error handling
 */
export const logAnalyticsEvent = (eventName: string, eventParams?: any) => {
  try {
    if (analytics) {
      logEvent(analytics, eventName, eventParams);
    }
  } catch (err) {
    console.warn('Analytics log failed:', err);
