import React, { useState, useEffect } from 'react';
import LoginView from './components/LoginView';
import PinSetupView from './components/PinSetupView';
import DashboardView from './components/DashboardView';
import InstallPrompt from './components/InstallPrompt';
import { ViewState, MemberData } from './types';
import { getMemberByPhone } from './services/membershipService';

function App() {
  const [viewState, setViewState] = useState<ViewState>(ViewState.LOGIN);
  const [memberData, setMemberData] = useState<MemberData | null>(null);
  const [setupPhone, setSetupPhone] = useState<string>('');
  const [isResetMode, setIsResetMode] = useState(false);
  const [isSessionLoading, setIsSessionLoading] = useState(true);

  // Initialize Theme
  useEffect(() => {
    const storedTheme = localStorage.getItem('theme');
    const prefersDark = window.matchMedia('(prefers-color-scheme: dark)').matches;
    const theme = storedTheme || (prefersDark ? 'dark' : 'light');
    document.documentElement.setAttribute('data-theme', theme);
  }, []);

  // Check for persisted session via LocalStorage
  useEffect(() => {
    const checkSession = async () => {
       const localSession = localStorage.getItem('hoa_session');
       if (localSession) {
          try {
             const session = JSON.parse(localSession);
             if (session.expiry > new Date().getTime()) {
                const member = await getMemberByPhone(session.phone);
                if (member) {
                   setMemberData(member);
                   setViewState(ViewState.DASHBOARD);
                } else {
                   localStorage.removeItem('hoa_session');
                }
             } else {
                localStorage.removeItem('hoa_session');
             }
          } catch (e) {
             localStorage.removeItem('hoa_session');
          }
       }
       setIsSessionLoading(false);
    };

    checkSession();
  }, []);

  const handleLoginSuccess = (data: MemberData) => {
    setMemberData(data);
    setViewState(ViewState.DASHBOARD);
  };

  const handleRequireSetup = (phone: string) => {
    setSetupPhone(phone);
    setIsResetMode(false);
    setViewState(ViewState.SETUP_PIN);
  };

  const handleForgotPassword = (phone: string) => {
    setSetupPhone(phone);
    setIsResetMode(true);
    setViewState(ViewState.SETUP_PIN);
  };

  const handleLogout = () => {
    localStorage.removeItem('hoa_session');
    setMemberData(null);
    setSetupPhone('');
    setIsResetMode(false);
    setViewState(ViewState.LOGIN);
  };

  const handleSetupSuccess = (member: MemberData) => {
    setMemberData(member);
    setViewState(ViewState.DASHBOARD);
    setSetupPhone('');
    setIsResetMode(false);

    localStorage.setItem('hoa_session', JSON.stringify({
       phone: member.phone.replace(/[\s\-\(\)]/g, ''),
       expiry: new Date().getTime() + (30 * 24 * 60 * 60 * 1000)
    }));
  };

  const handleSetupBack = () => {
    setViewState(ViewState.LOGIN);
    setSetupPhone('');
    setIsResetMode(false);
  };

  if (isSessionLoading) {
    return (
      <div className="min-h-screen bg-brand-black flex items-center justify-center">
        <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-brand-accent"></div>
      </div>
    );
  }

  return (
    <>
      {viewState === ViewState.LOGIN && (
        <LoginView 
          onLoginSuccess={handleLoginSuccess} 
          onRequireSetup={handleRequireSetup}
          onForgotPassword={handleForgotPassword}
        />
      )}

      {viewState === ViewState.SETUP_PIN && (
        <PinSetupView 
          phone={setupPhone}
          onSuccess={handleSetupSuccess}
          onBack={handleSetupBack}
          isReset={isResetMode}
        />
      )}

      {viewState === ViewState.DASHBOARD && memberData && (
        <DashboardView 
          member={memberData} 
          onLogout={handleLogout} 
        />
      )}

      <InstallPrompt />
    </>
  );
}

export default App;

import React, { useState } from 'react';
import { DumbbellIcon, EyeIcon, EyeOffIcon } from './Icons';
import { verifyPhoneExists, login as sheetLogin } from '../services/membershipService';
import { logAnalyticsEvent } from '../services/firebase';
import { hashPin } from '../utils/encryption';
import { MemberData } from '../types';
import ThemeToggle from './ThemeToggle';

interface LoginViewProps {
  onLoginSuccess: (member: MemberData) => void;
  onRequireSetup: (phone: string) => void;
  onForgotPassword: (phone: string) => void;
}

const LoginView: React.FC<LoginViewProps> = ({ onLoginSuccess, onRequireSetup, onForgotPassword }) => {
  const [phone, setPhone] = useState('');
  const [pin, setPin] = useState('');
  const [showPin, setShowPin] = useState(false);
  const [rememberMe, setRememberMe] = useState(false);
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleLogin = async () => {
    setError('');
    setLoading(true);

    if (!phone || phone.length < 10) {
      setError('Please enter a valid phone number');
      setLoading(false);
      return;
    }

    if (!pin || pin.length !== 4) {
      setError('Please enter a 4-digit PIN');
      setLoading(false);
      return;
    }

    try {
      const hashedPin = hashPin(pin, phone);
      const result = await sheetLogin(phone, hashedPin);

      if (result.success && result.member) {
        // Successful login via Google Sheets
        localStorage.setItem('hoa_session', JSON.stringify({
           phone: phone.replace(/[\s\-\(\)]/g, ''),
           expiry: new Date().getTime() + (30 * 24 * 60 * 60 * 1000) // 30 days
        }));

        logAnalyticsEvent('user_login_success', { method: 'sheets_backend' });
        onLoginSuccess(result.member);
      } else if (result.needsSetup) {
        onRequireSetup(phone);
      } else {
        setError(result.error || 'Invalid PIN or Phone Number');
      }
    } catch (err) {
      setError('Login failed. Please check your connection.');
      console.error(err);
    }

    setLoading(false);
  };

  const handleForgotPasswordClick = async () => {
    setError('');
    if (!phone || phone.length < 10) {
      setError('Please enter your phone number to reset PIN');
      return;
    }

    setLoading(true);
    const result = await verifyPhoneExists(phone);
    setLoading(false);

    if (result.success) {
      onForgotPassword(phone);
    } else {
      setError(result.error || 'Phone number not found');
    }
  };

  return (
    <div className="min-h-screen bg-brand-black flex items-center justify-center p-4 relative">
      <div className="absolute top-4 right-4">
        <ThemeToggle />
      </div>

      <div className="bg-brand-dark rounded-lg shadow-xl p-8 w-full max-w-md border border-brand-border">
        <div className="text-center mb-8">
          <div className="inline-block p-4 bg-brand-accent/10 rounded-full mb-4 text-brand-accent">
            <DumbbellIcon />
          </div>
          <h1 className="text-3xl font-bold text-brand-textPrimary mb-2">CrossFit Lagos</h1>
          <p className="text-brand-accent font-semibold mb-1">Membership Portal</p>
          <p className="text-brand-textSecondary text-sm">Login to view your subscription</p>
        </div>

        <div className="space-y-4">
          <div>
            <label className="block text-sm font-medium text-brand-textSecondary mb-2">
              Phone Number
            </label>
            <input
              type="tel"
              value={phone}
              onChange={(e) => setPhone(e.target.value)}
              placeholder="Enter Phone Number"
              className="w-full px-4 py-3 bg-brand-input border border-brand-border rounded-lg focus:ring-2 focus:ring-brand-accent focus:border-transparent outline-none text-brand-textPrimary transition-all placeholder-brand-textSecondary/50"
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-brand-textSecondary mb-2">
              4-Digit PIN
            </label>
            <div className="relative">
              <input
                type={showPin ? 'text' : 'password'}
                value={pin}
                onChange={(e) => setPin(e.target.value.replace(/\D/g, '').slice(0, 4))}
                placeholder="••••"
                maxLength={4}
                className="w-full px-4 py-3 bg-brand-input border border-brand-border rounded-lg focus:ring-2 focus:ring-brand-accent focus:border-transparent outline-none pr-12 text-brand-textPrimary transition-all placeholder-brand-textSecondary/50"
              />
              <button
                type="button"
                onClick={() => setShowPin(!showPin)}
                className="absolute right-3 top-1/2 -translate-y-1/2 text-brand-textSecondary hover:text-brand-accent"
              >
                {showPin ? <EyeOffIcon /> : <EyeIcon />}
              </button>
            </div>

            <div className="flex justify-between items-start mt-1">
              <div className="flex items-center">
                 <input 
                   id="remember-me"
                   type="checkbox" 
                   checked={rememberMe}
                   onChange={(e) => setRememberMe(e.target.checked)}
                   className="h-4 w-4 rounded border-brand-border bg-brand-input text-brand-accent focus:ring-brand-accent accent-brand-accent"
                 />
                 <label htmlFor="remember-me" className="ml-2 block text-xs text-brand-textSecondary cursor-pointer">
                   Remember me
                 </label>
              </div>
              <button 
                type="button"
                onClick={handleForgotPasswordClick}
                className="text-xs text-brand-accent hover:underline focus:outline-none"
              >
                Forgot/Setup PIN?
              </button>
            </div>
          </div>

          {error && (
            <div className="bg-brand-danger/10 border border-brand-danger text-brand-danger px-4 py-3 rounded-lg text-sm">
              {error}
            </div>
          )}

          <button
            onClick={handleLogin}
            disabled={loading}
            className="w-full bg-brand-accent text-brand-accentText py-3 rounded-lg font-bold hover:bg-brand-accentHover transition disabled:bg-gray-600 disabled:cursor-not-allowed"
          >
            {loading ? 'Logging in...' : 'Login'}
          </button>
        </div>
      </div>
    </div>
  );
};

export default LoginView;

import React, { useState } from 'react';
import { LockIcon, EyeIcon, EyeOffIcon } from './Icons';
