/**
 * Robust CSV parser that handles quoted strings and comma-separated values.
 */
export const parseCSV = (csvText: string): string[][] => {
  return csvText.split('\n').map(row => {
    const values: string[] = [];
    let current = '';
    let inQuotes = false;

    for (let i = 0; i < row.length; i++) {
      const char = row[i];
      if (char === '"') {
        inQuotes = !inQuotes;
      } else if (char === ',' && !inQuotes) {
        values.push(current.trim());
        current = '';
      } else {
        current += char;
      }
    }
    values.push(current.trim());
    return values;
  });
};

/**
 * Verifies if a phone number exists in the membership database.
 * Used for Forgot PIN and initial check flows.
 */
export const verifyPhoneExists = async (phone: string): Promise<{ success: boolean; error?: string }> => {
  try {
    const response = await fetch(SHEET_URL);
    if (!response.ok) throw new Error(`HTTP error! status: ${response.status}`);
    const csvText = await response.text();
    if (!csvText || csvText.trim().length === 0) return { success: false, error: 'Empty response from server' };

    const rows = parseCSV(csvText);
    const HEADER_ROW = 7; // Based on the standard CrossFit Lagos spreadsheet structure
    if (rows.length <= HEADER_ROW) return { success: false, error: 'Invalid data format from server' };

    const headers = rows[HEADER_ROW].map(h => h.replace(/[""]/g, '').trim());
    const data = rows.slice(HEADER_ROW + 1).filter(row => row.some(cell => cell && cell.trim()));

    const phoneIndex = headers.findIndex(h => {
      const normalized = h.toLowerCase().replace(/[""]/g, '').trim();
      return normalized === 'phone' || normalized.includes('phone');
    });

    if (phoneIndex === -1) return { success: false, error: `Phone column not found in sheet` };

    const cleanPhone = phone.replace(/\D/g, '').slice(-10); // Standardize to last 10 digits
    const memberRow = data.find(row => {
      const rowPhone = row[phoneIndex]?.replace(/\D/g, '');
      return rowPhone && rowPhone.endsWith(cleanPhone);
    });

    return memberRow ? { success: true } : { success: false, error: 'Phone number not found in our records' };
  } catch (err: any) {
    console.error('Verification error:', err);
    return { success: false, error: err.message || 'Unable to verify phone number.' };
  }
};

/**
 * Attempts to log in a member via the Apps Script API.
 * This is the primary authentication method.
 */
export const loginMember = async (phone: string, hashedPin: string): Promise<LoginResponse> => {
  try {
    const response = await fetch(SCRIPT_URL, {
      method: 'POST',
      redirect: 'follow', // Required for Google Apps Script redirects
      headers: { 'Content-Type': 'text/plain;charset=utf-8' },
      body: JSON.stringify({
        action: 'login',
        phone: phone,
        hashedPin: hashedPin
      })
    });

    if (!response.ok) throw new Error('Backend script unreachable');
    const result = await response.json();

    console.log('Auth API Result:', result);

    if (result.success) {
      if (result.member) return { success: true, member: result.member };
      if (result.needsPin) return { success: true, needsSetup: true };
    }

    // Explicitly handle common error codes from our Google Script
    if (result.error === 'invalidPin') return { success: false, error: 'Invalid PIN' };
    if (result.error === 'notFound') return { success: false, error: 'Phone number not found' };

    return { success: false, error: result.message || 'Login failed' };
  } catch (err) {
    console.warn('Direct script login failed, using Sheets CSV fallback:', err);
    // Fallback to fetchMemberData (local parsing of the public CSV)
    return fetchMemberData(phone, hashedPin);
  }
};

/**
 * Fallback login method that parses the published CSV locally.
 * Useful if the Apps Script POST endpoint is throttled or fails CORS.
 */
export const fetchMemberData = async (phone: string, hashedPin: string): Promise<LoginResponse> => {
  try {
    const response = await fetch(SHEET_URL);
    if (!response.ok) throw new Error(`HTTP error! status: ${response.status}`);
    const csvText = await response.text();
    if (!csvText || csvText.trim().length === 0) return { success: false, error: 'Empty response from server' };

    const rows = parseCSV(csvText);
    const HEADER_ROW = 7;
    if (rows.length <= HEADER_ROW) return { success: false, error: 'Invalid data format from server' };

    const headers = rows[HEADER_ROW].map(h => h.replace(/[""]/g, '').trim());
    const data = rows.slice(HEADER_ROW + 1).filter(row => row.some(cell => cell && cell.trim()));

    const phoneIndex = headers.findIndex(h => h.toLowerCase().includes('phone'));
    const pinIndex = headers.findIndex(h => h.toLowerCase().includes('pin'));

    const cleanPhone = phone.replace(/\D/g, '').slice(-10);
    const memberRow = data.find(row => {
      const rowPhone = row[phoneIndex]?.replace(/\D/g, '');
      return rowPhone && rowPhone.endsWith(cleanPhone);
    });

    if (!memberRow) return { success: false, error: 'Phone number not found' };

    const storedPin = memberRow[pinIndex];
    // If PIN field is blank or literally says "undefined", the user needs setup
    if (!storedPin || storedPin.toString().trim() === '' || storedPin.toString().trim() === 'undefined') {
      return { success: true, needsSetup: true };
    }

    // Validate the hashed PIN against the one stored in the sheet
    if (hashedPin.toString().trim() !== storedPin.toString().trim()) {
      return { success: false, error: 'Invalid PIN' };
    }

    const getField = (keyword: string) => {
        const idx = headers.findIndex(h => h.toLowerCase().includes(keyword.toLowerCase()));
        return idx !== -1 ? memberRow[idx] || '' : '';
    };

    const member: MemberData = {
      firstName: getField('First Name'),
      lastName: getField('Last Name'),
      email: getField('email'),
      phone: memberRow[phoneIndex] || '',
      package: getField('package'),
      amount: getField('amount'),
      duration: getField('duration'),
      startDate: getField('Start Date'),
      expirationDate: getField('Expiration Date'),
      status: getField('status'),
      pauseDays: getField('Pause Days') || '0'
    };

    return { success: true, member };
  } catch (err: any) {
    console.error('Fallback fetch error:', err);
    return { success: false, error: err.message || 'Unable to fetch membership data.' };
  }
};

