/**
 * Common fetch wrapper for Apps Script POST requests to handle CORS and redirects properly.
 */
async function callAppsScript(payload: any) {
  const controller = new AbortController();
  const timeoutId = setTimeout(() => controller.abort(), 15000); // 15s timeout

  try {
    const response = await fetch(SCRIPT_URL, {
      method: 'POST',
      mode: 'cors', // Explicitly set mode to cors
      redirect: 'follow', // Crucial for Google Apps Script redirects
      headers: {
        // Using text/plain avoids the pre-flight OPTIONS request in many browsers,
        // which Google Apps Script sometimes struggles to handle correctly.
        'Content-Type': 'text/plain;charset=utf-8',
      },
      body: JSON.stringify(payload),
      signal: controller.signal
    });

    clearTimeout(timeoutId);

    if (!response.ok) {
      throw new Error(`Server responded with status: ${response.status}`);
    }

    const text = await response.text();
    try {
      return JSON.parse(text);
    } catch (e) {
      console.error('[MembershipService] Failed to parse JSON response:', text);
      throw new Error('Invalid response format from server');
    }
  } catch (err: any) {
    clearTimeout(timeoutId);
    if (err.name === 'AbortError') {
      throw new Error('Request timed out. Please check your internet connection.');
    }
    throw err;
  }
}

