/**
 * House of Athletes - Google Apps Script Backend
 * Main file with login, PIN management, and token storage
 */

/**
 * Save notification token to member's row in sheet
 * Called from doPost when action === 'saveNotificationToken'
 * Updated to use your actual CONFIG values
 */
function saveNotificationToken(phone, token) {
  try {
    if (!phone || !token) {
      Logger.log('❌ Missing required parameters: phone=' + !!phone + ', token=' + !!token);
      return {
        success: false,
        message: 'Phone and token are required'
      };
    }

    const spreadsheet = SpreadsheetApp.getActiveSpreadsheet();
    const sheet = spreadsheet.getSheetByName(CONFIG.SHEET_NAME);

    if (!sheet) {
      Logger.log('❌ Sheet not found: ' + CONFIG.SHEET_NAME);
      return {
        success: false,
        message: 'Sheet not found: ' + CONFIG.SHEET_NAME
      };
    }

    const dataRange = sheet.getDataRange();
    const values = dataRange.getValues();

    // Your HEADERS_ROW is 8 (row 8 in the sheet)
    if (values.length < CONFIG.HEADERS_ROW) {
      Logger.log('❌ No data found in sheet');
      return {
        success: false,
        message: 'No data found in sheet'
      };
    }

    // Headers are at row 8 (index 7 in zero-based array)
    const headers = values[CONFIG.HEADERS_ROW - 1];
    const phoneIndex = headers.findIndex(h => h && h.toString().toLowerCase().includes('phone'));
    let tokenIndex = headers.findIndex(h => h && h.toString().toLowerCase().includes('notification token'));

    // Create Notification Token column if it doesn't exist
    if (tokenIndex === -1) {
      tokenIndex = headers.length;
      sheet.getRange(CONFIG.HEADERS_ROW, tokenIndex + 1).setValue('Notification Token');
      Logger.log('✅ Created Notification Token column at index: ' + tokenIndex);
    }

    if (phoneIndex === -1) {
      Logger.log('❌ Phone column not found in headers');
      return {
        success: false,
        message: 'Phone column not found in headers'
      };
    }

    // Clean phone numbers for comparison
    const cleanInputPhone = phone.toString().replace(/[\s\-\(\)]/g, '');
    const last10Digits = cleanInputPhone.slice(-10);

    Logger.log('Searching for phone: ' + phone + ' (last 10: ' + last10Digits + ')');

    // Search through data rows (starting from DATA_START_ROW which is 9)
    // In zero-based array, that's index 8
    for (let i = CONFIG.DATA_START_ROW - 1; i < values.length; i++) {
      const rowPhone = values[i][phoneIndex];

      if (!rowPhone) continue;

      const cleanRowPhone = rowPhone.toString().replace(/[\s\-\(\)]/g, '');
      const rowLast10 = cleanRowPhone.slice(-10);

      // Match by last 10 digits (handles different formats)
      if (rowLast10 === last10Digits) {
        // Update the token in the sheet
        const actualRow = i + 1; // Convert to 1-based row number
        sheet.getRange(actualRow, tokenIndex + 1).setValue(token);

        Logger.log('✅ Notification token saved for phone: ' + phone + ' at row: ' + actualRow);

        return {
