function setupPin(phone, hashedPin) {
  try {
    const spreadsheet = SpreadsheetApp.getActiveSpreadsheet();
    const sheet = spreadsheet.getSheetByName(CONFIG.SHEET_NAME);
    if (!sheet) {
      Logger.log('❌ Sheet not found: ' + CONFIG.SHEET_NAME);
