/**
 * Main web app entry point - handles POST requests
 */
function doPost(e) {
  try {
    const data = JSON.parse(e.postData.contents);
    const phone = data.phone;
    const action = data.action;

    Logger.log('📥 Request: action=' + action + ', phone=' + phone);

    if (!phone) {
      return ContentService.createTextOutput(JSON.stringify({
        success: false,
        message: 'Phone number is required'
      })).setMimeType(ContentService.MimeType.JSON);
    }

    // Handle different actions
    if (action === 'setupPin') {
      const hashedPin = data.hashedPin;
      if (!hashedPin) {
        return ContentService.createTextOutput(JSON.stringify({
          success: false,
          message: 'PIN is required'
        })).setMimeType(ContentService.MimeType.JSON);
      }

      return ContentService.createTextOutput(
        JSON.stringify(setupPin(phone, hashedPin))
      ).setMimeType(ContentService.MimeType.JSON);

    } else if (action === 'login') {
      const hashedPin = data.hashedPin;
      if (!hashedPin) {
        return ContentService.createTextOutput(JSON.stringify({
          success: false,
          message: 'PIN is required'
        })).setMimeType(ContentService.MimeType.JSON);
      }

      return ContentService.createTextOutput(
        JSON.stringify(loginMember(phone, hashedPin))
      ).setMimeType(ContentService.MimeType.JSON);

    } else if (action === 'getMember') {
      return ContentService.createTextOutput(
        JSON.stringify(getMemberByPhone(phone))
      ).setMimeType(ContentService.MimeType.JSON);

    } else if (action === 'saveNotificationToken') {
      const token = data.token;
      if (!token) {
        return ContentService.createTextOutput(JSON.stringify({
          success: false,
          message: 'Token is required'
        })).setMimeType(ContentService.MimeType.JSON);
      }

      return ContentService.createTextOutput(
        JSON.stringify(saveNotificationToken(phone, token))
      ).setMimeType(ContentService.MimeType.JSON);

      } else if (action === 'verifyPhone') {
      // Verify phone exists in database (for forgot PIN flow)
      const result = getMemberByPhone(phone);

      if (result.success && result.member) {
        return ContentService.createTextOutput(JSON.stringify({
          success: true,
          exists: true,
          message: 'Phone number verified'
        })).setMimeType(ContentService.MimeType.JSON);
      } else {
        return ContentService.createTextOutput(JSON.stringify({
          success: true,
          exists: false,
          message: 'Phone number not found in database'
        })).setMimeType(ContentService.MimeType.JSON);
      }

    } else {
      return ContentService.createTextOutput(JSON.stringify({
        success: false,
        message: 'Invalid action: ' + action
      })).setMimeType(ContentService.MimeType.JSON);
    }

  } catch (error) {
    Logger.log('❌ doPost error: ' + error.toString());
    return ContentService.createTextOutput(JSON.stringify({
      success: false,
      message: 'Server error: ' + error.toString()
    })).setMimeType(ContentService.MimeType.JSON);
  }
}

