function handleAnnouncements(ss, tz) {
  const SHEET_NAME = 'Announcements';
  const sheet = ss.getSheetByName(SHEET_NAME);

  if (!sheet) {
    return createJsonResponse({
      success: false,
      error: 'Announcements sheet not found'
    });
  }

  const now = new Date();
  const data = sheet.getDataRange().getValues();
  const headers = data.shift();

  const announcements = data
    .map(row => {
      let obj = {};
      headers.forEach((h, i) => obj[h] = row[i]);
      return obj;
    })
    .filter(a => {
      if (a.Active !== true) return false;

      if (a['Expiry Date']) {
        const expiry = new Date(a['Expiry Date']);
        if (expiry < now) return false;
      }

      return true;
    })
    .sort((a, b) => {
      // Newest first
      return new Date(b['Date Posted']) - new Date(a['Date Posted']);
    })
    .map(a => ({
      title: a.Title,
      message: a.Message,
      type: ['info', 'warning', 'urgent'].includes(
        String(a.Type).toLowerCase()
      ) ? String(a.Type).toLowerCase() : 'info',
      datePosted: a['Date Posted'],
      expiryDate: a['Expiry Date']
    }));

  return createJsonResponse({
    success: true,
    announcements
  });
}


