The console log reveals exactly why this is happening:

**Your script is returning Workout (WOD) data instead of Announcement data.**

When the app asks for `mode=announcements`, your Google Apps Script is ignoring that instruction and sending back today's workout instead. Here is the proof from your log:

*   The log shows: `data: { coach_notes: "...", workout: "Clean & Jerk..." }`
*   This is a **single object** (a workout), not an **array** (a list of announcements).

### The Fix (Check your Google Apps Script)
You need to open your Google Apps Script editor (`Code.gs`) and check your `doGet(e)` function. It likely looks like this:

```javascript
function doGet(e) {
  var mode = e.parameter.mode;

  // IT PROBABLY DEFAULTS TO THIS:
  if (mode === 'today' || !mode) {
    return getTodayWod(); 
  }

  // YOU MIGHT BE MISSING THIS PART:
  if (mode === 'announcements') {
    return getAnnouncements(); // Ensure this function exists and pulls from the correct tab
  }
}
```

### Why it's failing:
1.  **Logic Error:** Your script doesn't have a specific `if` statement for `mode === 'announcements'`, so it's just falling back to sending the "Workout of the Day."
2.  **Tab Name:** Ensure you have a tab in your Google Sheet named **"Announcements"** and that your script is correctly coded to read from it.

**Summary:** The frontend app is working perfectly—it's successfully talking to your script. The script just needs to be updated to actually send the announcements when asked!

/**
 * GET Request Handler
 * Used for fetching announcements, WODs, and checking Pause Status.
 */
function doGet(e) {
  try {
    const ss = SpreadsheetApp.getActiveSpreadsheet();
    const tz = ss.getSpreadsheetTimeZone();

    // Get parameters from URL
    const mode = (e && e.parameter && e.parameter.mode) || 'today';
    const userId = e && e.parameter && e.parameter.userId;

    // --- ROUTING ---
    if (mode === 'announcements') {
      return handleAnnouncements(ss, tz);
    } else if (mode === 'pauseStatus') {
      return handlePauseStatus(ss, userId);
    } else {
      // Default: Handles WOD requests
      return handleWodRequest(ss, tz, mode, userId);
    }

  } catch (error) {
    return createJsonResponse({ success: false, error: error.toString() });
  }
}

/**
 * CrossFit Lagos WOD API v2.1
 * Updated for dd-MM-yyyy date format
 */

function doGet(e) {
  try {
    const ss = SpreadsheetApp.getActiveSpreadsheet();
    const sheet = ss.getSheetByName("WOD");

    const mode = (e && e.parameter && e.parameter.mode) || 'today';

    if (!sheet) return createJsonResponse({ error: "Sheet tab 'WOD' not found." });

    const data = sheet.getDataRange().getValues();
    if (data.length < 2) return createJsonResponse({ error: "Sheet is empty." });

    const headers = data.shift();
    const tz = ss.getSpreadsheetTimeZone();

    if (mode === 'history') {
      return handleHistoryMode(data, tz);
    } else {
      return handleTodayMode(data, tz);
    }

  } catch (error) {
    return createJsonResponse({ error: error.toString() });
  }
}

function handleHistoryMode(data, tz) {
  const history = [];
  const today = new Date();
  today.setHours(0, 0, 0, 0);

  for (let row of data) {
    if (!row[0]) continue;
    const cellDate = row[0] instanceof Date ? row[0] : new Date(row[0]);

    // Calculate difference to show only last 7 days
    const diffDays = (today - cellDate) / (1000 * 60 * 60 * 24);

    if (diffDays >= 0 && diffDays <= 7) {
      history.push({
        date: Utilities.formatDate(cellDate, tz, "dd-MM-yyyy"), // Updated Format
        displayDate: Utilities.formatDate(cellDate, tz, "EEE, d MMM"), // e.g. "Mon, 22 Dec"
        workout: row[1],
        coach_notes: row[2] || ""
      });
    }
  }

  history.sort((a, b) => {
    // Correct sorting for dd-MM-yyyy strings
    const dateA = a.date.split('-').reverse().join('-');
    const dateB = b.date.split('-').reverse().join('-');
    return new Date(dateB) - new Date(dateA);
  });

  return createJsonResponse({ success: true, count: history.length, data: history });
}

function handleTodayMode(data, tz) {
  const todayStr = Utilities.formatDate(new Date(), tz, "dd-MM-yyyy"); // Updated Format

  for (let row of data) {
    if (!row[0]) continue;
    const cellDate = row[0] instanceof Date ? row[0] : new Date(row[0]);
    const rowDateStr = Utilities.formatDate(cellDate, tz, "dd-MM-yyyy"); // Updated Format

    if (rowDateStr === todayStr) {
      return createJsonResponse({
        success: true,
        data: {
          date: rowDateStr,
          workout: row[1],
          coach_notes: row[2] || ""
        }
      });
    }
  }
  return createJsonResponse({ success: false, message: "No WOD found for " + todayStr });
}

function createJsonResponse(payload) {
  return ContentService.createTextOutput(JSON.stringify(payload))
    .setMimeType(ContentService.MimeType.JSON);
}

