      if (!sheet) return createJsonResponse({ success: false, error: "Sheet tab 'WOD' not found." });

      const data = sheet.getDataRange().getValues();
      if (data.length < 2) return createJsonResponse({ success: false, error: "Sheet is empty." });

      data.shift(); // remove headers
      if (mode === 'history') return handleHistoryMode(data, tz);
      return handleTodayMode(data, tz);
    } 
    else {
      return createJsonResponse({ success: false, error: "Invalid mode parameter." });
    }

  } catch (error) {
    return createJsonResponse({ success: false, error: error.toString() });
  }
}

/**
 * Announcements handler (with isNew flag)
 */
function handleAnnouncements(ss, tz) {
  ss = ss || SpreadsheetApp.getActiveSpreadsheet();
  const SHEET_NAME = 'Announcements';
  const sheet = ss.getSheetByName(SHEET_NAME);

  if (!sheet) {
    return createJsonResponse({
      success: false,
      data: { announcements: [] },
      error: 'Announcements sheet not found'
    });
  }

  const now = new Date();
  const data = sheet.getDataRange().getValues();
  const headers = data.shift();

  const announcements = data
    .map(row => {
      let obj = {};
      headers.forEach((h, i) => obj[h] = row[i]);
      return obj;
    })
    .filter(a => {
      if (a.Active !== true) return false;
      if (a['Expiry Date']) {
        const expiry = new Date(a['Expiry Date']);
        if (expiry < now) return false;
      }
      return true;
    })
    .sort((a, b) => new Date(b['Date Posted']) - new Date(a['Date Posted']))
    .map(a => ({
      title: a.Title,
      message: a.Message,
      type: ['info', 'warning', 'urgent'].includes(
        String(a.Type).toLowerCase()
      ) ? String(a.Type).toLowerCase() : 'info',
      datePosted: a['Date Posted'],
      expiryDate: a['Expiry Date'],
      isNew: true // Frontend can mark as seen using local storage
    }));

  return createJsonResponse({
    success: true,
    data: { announcements: announcements }
  });
}

/**
 * Utility: JSON response
 */
function createJsonResponse(payload) {
  return ContentService.createTextOutput(JSON.stringify(payload))
    .setMimeType(ContentService.MimeType.JSON);
