  message: string;
  type: 'info' | 'warning' | 'urgent';
  datePosted: string;
  expiryDate?: string;
  isNew?: boolean;
}

export enum ViewState {
  LOGIN,
  SETUP_PIN,
  DASHBOARD
}

export interface LoginResponse {
  success: boolean;
  needsSetup?: boolean;
  member?: MemberData;
  error?: string;
  invalidPin?: boolean;
}

export type PauseStatus = 'Pending' | 'Approved' | 'Denied' | 'None';

export interface PauseStatusResponse {
  success: boolean;
  status: PauseStatus;
  message?: string;
