    .map(row => {
      let obj = {};
      headers.forEach((h, i) => obj[h] = row[i]);
      return obj;
    })
    .filter(a => {
      if (a.Active !== true) return false;
      if (a['Expiry Date']) {
        const expiry = new Date(a['Expiry Date']);
        if (expiry < now) return false;
      }
      return true;
    })
    .sort((a, b) => new Date(b['Date Posted']) - new Date(a['Date Posted']))
    .map(a => ({
      title: a.Title,
      message: a.Message,
      type: ['info', 'warning', 'urgent'].includes(
        String(a.Type).toLowerCase()
      ) ? String(a.Type).toLowerCase() : 'info',
      datePosted: a['Date Posted'],
      expiryDate: a['Expiry Date'],
      isNew: true
    }));

  return createJsonResponse({
    success: true,
    data: { announcements: announcements }
  });
}

/**
 * WOD handler for today's workout
 */
function handleTodayMode(data, tz) {
  const todayStr = Utilities.formatDate(new Date(), tz, "dd-MM-yyyy");

  for (let row of data) {
    if (!row[0]) continue;

    let cellDate;
    if (row[0] instanceof Date) {
      cellDate = row[0];
    } else {
      const parts = String(row[0]).split("-");
      if (parts.length === 3) {
        const day = parseInt(parts[0], 10);
        const month = parseInt(parts[1], 10) - 1;
        const year = parseInt(parts[2], 10);
        cellDate = new Date(year, month, day);
      } else {
        continue;
      }
    }

    const rowDateStr = Utilities.formatDate(cellDate, tz, "dd-MM-yyyy");

    if (rowDateStr === todayStr) {
      return createJsonResponse({
        success: true,
        data: {
          date: rowDateStr,
          workout: row[1],       // Workout (Description)
          coach_notes: row[2] || ""
        }
      });
    }
  }

  return createJsonResponse({ success: false, message: "No WOD found for " + todayStr });
}

/**
 * WOD handler for last 7 days (history)
 */
function handleHistoryMode(data, tz) {
  const history = [];
  const today = new Date();
  today.setHours(0,0,0,0);

  for (let row of data) {
    if (!row[0]) continue;

    let cellDate;
    if (row[0] instanceof Date) {
      cellDate = row[0];
    } else {
      const parts = String(row[0]).split("-");
      if (parts.length === 3) {
        const day = parseInt(parts[0], 10);
        const month = parseInt(parts[1], 10) - 1;
        const year = parseInt(parts[2], 10);
        cellDate = new Date(year, month, day);
      } else {
        continue;
      }
    }

    const diffDays = (today - cellDate) / (1000*60*60*24);
    if (diffDays >=0 && diffDays <= 7) {
      history.push({
        date: Utilities.formatDate(cellDate, tz, "dd-MM-yyyy"),
        displayDate: Utilities.formatDate(cellDate, tz, "EEE, d MMM"),
        workout: row[1],
        coach_notes: row[2] || ""
      });
    }
  }

  history.sort((a,b) => {
    const dateA = a.date.split('-').reverse().join('-');
    const dateB = b.date.split('-').reverse().join('-');
    return new Date(dateB) - new Date(dateA);
  });

  return createJsonResponse({ success: true, count: history.length, data: history });
}

/**
 * Utility: JSON response
 */
function createJsonResponse(payload) {
  return ContentService.createTextOutput(JSON.stringify(payload))
    .setMimeType(ContentService.MimeType.JSON);
}


